import { createVercelAISDK } from '@vex_dev/sdk/vercel';
import { streamText } from 'ai';

const vex = createVercelAISDK({
  policies: ['fintech-hallucination-guard', 'sox-financial-disclosure'],
  rules: {
    prependDisclaimer: 'This is not personalized financial advice. Consult a licensed advisor.',
    validateFacts: ['stock prices', 'regulatory compliance']
  }
});

export async function streamFinancialAdvice(userQuery: string) {
  const result = await streamText({
    model: openai('gpt-4o'),
    prompt: userQuery,
    middleware: vex.middleware()
  });
  return result;
}

